final:
module RefModule(
    input clk,
    input reset,
    input shift,
    output reg [4:0] q);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        q <= 5'b00000;
    else if (shift)
        q <= {q[0], q[4:1]};
end
endmodule
